import java.util.*;

public interface UserRepository {
    Optional<User> findById(int id);
    List<User> findAll();
    User save(User user);
    void deleteById(int id);
}

public class User {
    private int id;
    private String name;
    public User(int id, String name) { this.id = id; this.name = name; }
    public int getId() { return id; }
    public String getName() { return name; }
    @Override public String toString() { return "User{" + id + ", " + name + "}"; }
}

public class MockUserRepository implements UserRepository {
    private Map<String, Object> stubbedReturns = new HashMap<>();
    private List<String> callLog = new ArrayList<>();

    // Stub setup: stub("findById_1", Optional.of(user))
    public void stub(String callKey, Object returnValue) {
        stubbedReturns.put(callKey, returnValue);
    }

    private void recordCall(String callSignature) {
        callLog.add(callSignature);
    }

    @Override
    @SuppressWarnings("unchecked")
    public Optional<User> findById(int id) {
        recordCall("findById(" + id + ")");
        return (Optional<User>) stubbedReturns.getOrDefault("findById_" + id, Optional.empty());
    }

    @Override
    @SuppressWarnings("unchecked")
    public List<User> findAll() {
        recordCall("findAll()");
        return (List<User>) stubbedReturns.getOrDefault("findAll", new ArrayList<>());
    }

    @Override
    public User save(User user) {
        // TODO: Record call and return stubbed value or the user itself
        return user;
    }

    @Override
    public void deleteById(int id) {
        // TODO: Record the call
    }

    public boolean wasCalled(String method) {
        return callLog.stream().anyMatch(c -> c.contains(method));
    }

    public int callCount(String methodPrefix) {
        return (int) callLog.stream().filter(c -> c.startsWith(methodPrefix)).count();
    }

    public List<String> getCallLog() { return Collections.unmodifiableList(callLog); }
}

public class UserService {
    private UserRepository repository;

    public UserService(UserRepository repository) {
        this.repository = repository;
    }

    public String getUserName(int id) {
        return repository.findById(id)
            .map(User::getName)
            .orElse("Unknown");
    }

    public int getTotalUsers() {
        return repository.findAll().size();
    }
}

public class Main {
    public static void main(String[] args) {
        MockUserRepository mockRepo = new MockUserRepository();

        // Stub responses
        mockRepo.stub("findById_1", Optional.of(new User(1, "Alice")));
        mockRepo.stub("findAll", Arrays.asList(new User(1, "Alice"), new User(2, "Bob")));

        UserService service = new UserService(mockRepo);

        System.out.println(service.getUserName(1));       // Should print Alice
        System.out.println(service.getUserName(99));      // Should print Unknown
        System.out.println(service.getTotalUsers());      // Should print 2

        System.out.println("findById called: " + mockRepo.wasCalled("findById"));
        System.out.println("findById call count: " + mockRepo.callCount("findById"));
        System.out.println("Call log: " + mockRepo.getCallLog());
    }
}

import java.util.*;

public interface EmailService {
    void sendWelcomeEmail(String to);
    void sendOrderConfirmation(String to, int orderId);
    void sendPasswordReset(String to, String token);
}

public class TrackingEmailService implements EmailService {
    private List<String[]> calls = new ArrayList<>();

    @Override
    public void sendWelcomeEmail(String to) {
        calls.add(new String[]{"sendWelcomeEmail", to});
    }

    @Override
    public void sendOrderConfirmation(String to, int orderId) {
        calls.add(new String[]{"sendOrderConfirmation", to, String.valueOf(orderId)});
    }

    @Override
    public void sendPasswordReset(String to, String token) {
        calls.add(new String[]{"sendPasswordReset", to, token});
    }

    public boolean verifyCalledOnceWith(String method, String... args) {
        long count = calls.stream().filter(call -> {
            if (!call[0].equals(method)) return false;
            for (int i = 0; i < args.length; i++) {
                if (i + 1 >= call.length || !call[i + 1].equals(args[i])) return false;
            }
            return true;
        }).count();
        return count == 1;
    }

    public boolean verifyNeverCalled(String method) {
        return calls.stream().noneMatch(call -> call[0].equals(method));
    }
}

public class UserRegistrationService {
    private EmailService emailService;

    public UserRegistrationService(EmailService emailService) {
        this.emailService = emailService;
    }

    public void register(String email) {
        // Simulate registration
        System.out.println("Registering user: " + email);
        emailService.sendWelcomeEmail(email);
        // Note: Should NOT send order confirmation on registration
    }
}

public class Main {
    public static void main(String[] args) {
        TrackingEmailService mockEmail = new TrackingEmailService();
        UserRegistrationService service = new UserRegistrationService(mockEmail);

        service.register("alice@example.com");

        // Verify interactions
        boolean welcomeSent = mockEmail.verifyCalledOnceWith("sendWelcomeEmail", "alice@example.com");
        boolean orderConfirmNotSent = mockEmail.verifyNeverCalled("sendOrderConfirmation");
        boolean passwordResetNotSent = mockEmail.verifyNeverCalled("sendPasswordReset");

        System.out.println("Welcome email sent: " + welcomeSent);
        System.out.println("Order confirmation NOT sent: " + orderConfirmNotSent);
        System.out.println("Password reset NOT sent: " + passwordResetNotSent);
        System.out.println("All interactions verified: " + (welcomeSent && orderConfirmNotSent && passwordResetNotSent));
    }
}

import java.util.*;

public class InventoryService {
    private Map<String, Integer> stock = new HashMap<>();

    public void addStock(String product, int quantity) {
        stock.merge(product, quantity, Integer::sum);
    }

    public int getStock(String product) {
        return stock.getOrDefault(product, 0);
    }

    public boolean reserveStock(String product, int quantity) {
        int current = getStock(product);
        if (current >= quantity) {
            stock.put(product, current - quantity);
            return true;
        }
        return false;
    }

    public void sendLowStockAlert(String product) {
        // In production: sends email/notification
        System.out.println("ALERT: Low stock for " + product);
    }

    public boolean checkAndReserve(String product, int quantity) {
        boolean reserved = reserveStock(product, quantity);
        if (getStock(product) < 5) {
            sendLowStockAlert(product);
        }
        return reserved;
    }
}

public class SpyInventoryService extends InventoryService {
    private List<String> alertsSuppressed = new ArrayList<>();
    private boolean suppressAlerts = false;

    public void setSuppressAlerts(boolean suppress) {
        this.suppressAlerts = suppress;
    }

    @Override
    public void sendLowStockAlert(String product) {
        if (suppressAlerts) {
            // Spy behavior: suppress the side effect but record the call
            alertsSuppressed.add(product);
        } else {
            super.sendLowStockAlert(product);
        }
    }

    public List<String> getAlertsTriggered() { return alertsSuppressed; }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("--- Spy: Uses real logic, suppresses alert side effect ---");
        SpyInventoryService spy = new SpyInventoryService();
        spy.setSuppressAlerts(true);
        spy.addStock("Laptop", 6);

        boolean reserved = spy.checkAndReserve("Laptop", 4); // Leaves 2 < 5 -> alert triggered
        System.out.println("Reserved: " + reserved);
        System.out.println("Remaining stock: " + spy.getStock("Laptop"));
        System.out.println("Alerts suppressed for: " + spy.getAlertsTriggered());

        System.out.println("\n--- Real object: alert fires in console ---");
        InventoryService real = new InventoryService();
        real.addStock("Mouse", 3);
        real.checkAndReserve("Mouse", 0); // Starts below 5, alert fires
    }
}
